import React, { useState, useRef } from 'react';
import { theme, fonts, TEMPLATES } from './theme';
import { Btn, SectionCard, Label, Input } from './components/UI';
import LeftPanel from './components/LeftPanel';
import PreviewDoc from './components/PreviewDoc';
import { exportToPDF } from './pdfExport';

export default function App() {
  const [step, setStep] = useState('editor');
  const [templateKey, setTemplateKey] = useState('DAA');
  const [tpl, setTpl] = useState({ ...TEMPLATES.DAA });
  const [studentName, setStudentName] = useState('Prem');
  const [uid, setUid] = useState('24bcs12219');
  const [section, setSection] = useState('612 A');
  const [worksheetNo, setWorksheetNo] = useState('4');
  const [datePerf, setDatePerf] = useState('02-04-2026');

  const [sectionContent, setSectionContent] = useState({
    Aim: '',
    Requirements: '',
    'Procedure/Code': '',
    Output: '',
    'Learning Outcome': '',
  });

  const [outputImages, setOutputImages] = useState([]);
  const [generating, setGenerating] = useState(null);
  const [exporting, setExporting] = useState(false);
  const [savedTemplates, setSavedTemplates] = useState([]);

  const previewRef = useRef(null);

  const handleTemplateChange = (key) => {
    setTemplateKey(key);
    setTpl({ ...TEMPLATES[key] });
  };

  const updateTpl = (k, v) => setTpl(prev => ({ ...prev, [k]: v }));
  const updateContent = (sec, val) => setSectionContent(prev => ({ ...prev, [sec]: val }));

  const handleImageUpload = (e) => {
    const files = Array.from(e.target.files);
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setOutputImages(prev => [...prev, { name: file.name, dataUrl: ev.target.result }]);
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (idx) => setOutputImages(prev => prev.filter((_, i) => i !== idx));

  const handleDownloadPDF = () => {
    setExporting(true);
    try {
      const name = `Worksheet-${worksheetNo}-${studentName || 'Student'}`;
      exportToPDF({ tpl, studentName, uid, section, worksheetNo, datePerf, sectionContent, outputImages }, name);
    } catch (e) {
      alert('PDF export failed');
    }
    setExporting(false);
  };

  // ✅ AI Enhance (Ollama)
  const aiEnhance = async (sec) => {
    setGenerating(sec);
    try {
      const res = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "llama3",
          prompt: `Improve the English and clarity of this text:\n${sectionContent[sec]}`,
          stream: false
        }),
      });

      const data = await res.json();
      if (data.response) {
        updateContent(sec, data.response.trim());
      }
    } catch (e) {
      alert("Start Ollama: ollama run llama3");
    }
    setGenerating(null);
  };

  // ✅ AI Auto Fill (Ollama)
  const aiAutoFill = async () => {
    setGenerating('all');
    try {
      const res = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "llama3",
          prompt: `Generate content for all sections of a CS worksheet.
Subject: ${tpl.subject}
Sections: ${tpl.sections.join(', ')}

Return ONLY JSON:
{
  "Aim": "...",
  "Requirements": "...",
  "Procedure/Code": "...",
  "Output": "...",
  "Learning Outcome": "..."
}`,
          stream: false
        }),
      });

      const data = await res.json();
      const parsed = JSON.parse(data.response);
      setSectionContent(prev => ({ ...prev, ...parsed }));

    } catch (e) {
      alert("Ollama not running or invalid response");
    }
    setGenerating(null);
  };

  const saveTemplate = () => {
    const name = `Template ${savedTemplates.length + 1}`;
    setSavedTemplates(prev => [...prev, { name, tpl, content: sectionContent }]);
  };

  const loadTemplate = (s) => {
    setTpl(s.tpl);
    setSectionContent(s.content);
  };

  return (
    <div style={{ minHeight: '100vh', background: theme.bg, color: theme.text }}>

      {/* TOP BAR */}
      <div style={{
        background: theme.surface,
        borderBottom: `1px solid ${theme.border}`,
        padding: '14px 28px',
        display: 'flex',
        justifyContent: 'space-between'
      }}>
        <div style={{ fontWeight: 700 }}>AssessSheet</div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Btn onClick={() => setStep('editor')}>Editor</Btn>
          <Btn onClick={() => setStep('preview')}>Preview</Btn>
        </div>
      </div>

      {step === 'editor' && (
        <div style={{ display: 'flex' }}>
          <LeftPanel
            tpl={tpl}
            updateTpl={updateTpl}
            templateKey={templateKey}
            handleTemplateChange={handleTemplateChange}
            savedTemplates={savedTemplates}
            saveTemplate={saveTemplate}
            loadTemplate={loadTemplate}
          />

          <div style={{ flex: 1, padding: 20 }}>

            <SectionCard title="AI Auto Fill">
              <Btn onClick={aiAutoFill}>
                {generating === 'all' ? 'Generating...' : 'Auto Fill'}
              </Btn>
            </SectionCard>

            {tpl.sections.map(sec => (
              <SectionCard key={sec} title={sec}>
                <Input
                  multiline
                  rows={5}
                  value={sectionContent[sec]}
                  onChange={v => updateContent(sec, v)}
                />
                <Btn onClick={() => aiEnhance(sec)}>
                  {generating === sec ? 'Improving...' : 'Improve English'}
                </Btn>
              </SectionCard>
            ))}

            <Btn onClick={() => setStep('preview')}>Preview</Btn>

          </div>
        </div>
      )}

      {step === 'preview' && (
        <div style={{ padding: 20 }}>
          <PreviewDoc
            ref={previewRef}
            tpl={tpl}
            studentName={studentName}
            uid={uid}
            section={section}
            worksheetNo={worksheetNo}
            datePerf={datePerf}
            sectionContent={sectionContent}
            outputImages={outputImages}
          />
          <Btn onClick={handleDownloadPDF}>
            {exporting ? 'Generating...' : 'Download PDF'}
          </Btn>
        </div>
      )}

    </div>
  );
}
